		var HOPE = new Array();
var hi, hf;

function Load()
{
	if(Ctrl("main").GetMode()=="SHOW" || Ctrl("main").GetMode()=="EDIT")
	{
		//alert("SHOW");
		Ctrl('e_horainicio').SetXValue(int2time(Ctrl('hide_horainicio').GetXValue()));
		Ctrl('e_horafin').SetXValue(int2time(Ctrl('hide_horafin').GetXValue()));
	} 
}

function int2time(MyTIME)
{
	var hh = FillLeft(Math.floor((Number(MyTIME)+Number(1440))%1440/60).toString(),2,"0");
	var mm = FillLeft(((Number(MyTIME)+Number(1440)) % 60).toString(),2,"0");

	return hh+mm;

	//return Math.floor((MyTIME+1440)%1440/60)+FillLeft(((MyTIME+1440) % 60).toString(),2,"0");
}

function Validar()
{             
	//alert(1);
	//return false;

	if(Ctrl("main").GetMode()=="NEW" || Ctrl("main").GetMode()=="EDIT")
	{ 
		NomadTimeout("", 200, "Validando...");

		var bndNuevo = false;

		if(Ctrl("main").GetMode()=="NEW")
		{
			var strDT = datetime2str(str2datetime(Ctrl("f_fecha").GetXValue()));
			Ctrl('hidid').SetXValue("#"+strDT);
			bndNuevo = true;
		}

		var hinicio = Ctrl('e_horainicio').GetXValue().toString().substr(0,4);
		var hfin = Ctrl('e_horafin').GetXValue().toString().substr(0,4);

		hi = time2int(hinicio);
		if(hinicio<hfin)		
			hf = time2int(hfin);
		else
			hf = time2int(Number(hfin)+2400);

	 	if(EditAccept())
	 	{ 	 	  			
			Ctrl('hide_horainicio').SetXValue(hi);
			Ctrl('hide_horafin').SetXValue(hf); 

			if(!bndNuevo)
			{
				for (t=0; t<Ctrl("arrNovedades").CountRow(); t++)
				{
					MyROW=Ctrl("arrNovedades").GetRow(t);

					if (MyROW.GetAttr("id")==Ctrl('hidid').GetXValue())
					{
						MyROW.SetAttr("f_fecha",Ctrl("f_fecha").GetXValue());
						MyROW.SetAttr("e_horainicio",hi);
						MyROW.SetAttr("e_horafin",hf); 
						MyROW.SetAttr("oi_tipohora"  ,Ctrl("oi_tipohora").GetXValue());
						MyROW.SetAttr("d_novedad"    ,Ctrl("d_novedad").GetXValue());
						MyROW.SetAttr("oi_estructura",Ctrl("oi_estructura").GetXValue());
						MyROW.SetAttr("o_novedad"    ,Ctrl("o_novedad").GetXValue());

						break;
					}
				}
			}
			else
			{
				/*MyROW=Ctrl("arrNovedades").AddRow();
				MyROW.SetAttr("f_fecha",Ctrl("f_fecha").GetXValue());
				MyROW.SetAttr("e_horainicio",hi);
				MyROW.SetAttr("e_horafin",hf); 
				MyROW.SetAttr("oi_tipohora"  ,Ctrl("oi_tipohora").GetXValue());
				MyROW.SetAttr("d_novedad"    ,Ctrl("d_novedad").GetXValue());
				MyROW.SetAttr("oi_estructura",Ctrl("oi_estructura").GetXValue());
				MyROW.SetAttr("o_novedad"    ,Ctrl("o_novedad").GetXValue()); */
			}

			return true;
	 	}
	 	else
	 		return false; 

	}
	else
		return true;
}

function time2int(Time)
{
	var acum = 0;
	acum += (Number(Time.toString().substr(0,2)))*60;

	acum += Number(Time.toString().substr(2,2));


	return acum;
}

function EditAccept()
{    
	var t;

	var sd=Math.floor((str2date(Ctrl("f_fecha").GetXValue())-str2date("20000102"))/60000);
	var ds=sd+parseInt(hi,10);
	var de=sd+parseInt(hf,10);

	var sd_check;
	var ds_check;
	var de_check;

	var myDate,MyHopeDay;

  //Veririco las Novedades
	for (t=0; t<Ctrl("arrNovedades").CountRow(); t++)
	{
		MyROW=Ctrl("arrNovedades").GetRow(t);
		if (MyROW.GetAttr("id")==Ctrl('hidid').GetXValue())
			continue;

		sd_check=Math.floor((str2date(MyROW.GetAttr("f_fecha"))-str2date("20000102"))/60000);
		ds_check=sd_check+parseInt(MyROW.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(MyROW.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad actual se superpone con otra Novedad.");
		return false;
	}

	//Verifico contra la esperanza                                             
	myDate=str2date(Ctrl("f_fecha").GetXValue());
	myDate.setDate(myDate.getDate()-1);
	MyHopeDay=GetHope(Math.floor((myDate-str2date("20000102"))/604800000)).FindElement2("DIA","f_dia",date2str(myDate));

  sd_check=Math.floor((myDate-str2date("20000102"))/60000);
	if (MyHopeDay!=null)
	for (cur=MyHopeDay.FindElement("DETALLE").FirstChild(); cur!=null; cur=cur.Next())
	{            
		ds_check=sd_check+parseInt(cur.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(cur.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad actual se superpone con una esperanza del dia anterior.");
		return false;
	}

	//Verifico contra la esperanza                                             
	myDate=str2date(Ctrl("f_fecha").GetXValue());
	myDate.setDate(myDate.getDate()+1);
	MyHopeDay=GetHope(Math.floor((myDate-str2date("20000102"))/604800000)).FindElement2("DIA","f_dia",date2str(myDate));

  sd_check=Math.floor((myDate-str2date("20000102"))/60000);
	if (MyHopeDay!=null)
	for (cur=MyHopeDay.FindElement("DETALLE").FirstChild(); cur!=null; cur=cur.Next())
	{            
		ds_check=sd_check+parseInt(cur.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(cur.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad se superpone con una esperanza del dia posterior.");
		return false;
	}

	return true;
}


function GetHope(semana)
{                                              
	//Busca en el CACHE
	if (HOPE["K"+semana]) return HOPE["K"+semana];

  //Cargo la HOPE
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();
	var retval;

	RPC.AddParam(new NomadRPCParam("week"    , "IN" , parseInt(semana,10)));
	RPC.AddParam(new NomadRPCParam("personal", "IN" , parseInt(Ctrl("oi_personal_emp").GetXValue(),10)));
	RPC.AddParam(new NomadRPCParamOut("retval", "Nomad.NSystem.Object", "NucleusRH.Base.Tiempos_Trabajados.Esperanzaper.ESPERANZAPER"));

	RPC.Execute("NucleusRH.Base.Tiempos_Trabajados.Esperanzaper.ESPERANZAPER","GetHope");
	retval=new NomadXML(RPC.GetParam("retval").Data); 

	//Agrego el elemento al CACHE
	HOPE["K"+semana]=retval.FirstChild().FindElement("DIAS");
	return HOPE["K"+semana];
}

		function Find()
{
	Ctrl("LIST").filter("",Ctrl("iter_search").GetCValue());
}
function Imprimir()
{  
	Ctrl("LIST").toPrinter(Ctrl("ti_01").GetCValue());
}
function ToList()
{                
	if (parseInt(Ctrl("iter_size").GetXValue(),10)<=300)
	{
		if(Validar())
			Ctrl("LISTA").DoEvent("showList");
	}
	else
		showMess("Modo Lista", "Demasiados registros para ser mostrados en una lista.");
}                                                  

